#define fp float

#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
	fp x, y, z;
} THREE_VECTOR;

typedef struct {
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str {
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str {
	fp alpha;
} par_str;

typedef struct dim_str {
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void
kernel_gpu_opencl(par_str par,
                  dim_str dim,
                  __global box_str* box,
                  __global FOUR_VECTOR* rv,
                  __global fp* qv,
                  __global FOUR_VECTOR* fv)
{
	int tx = (int)get_local_id(0);
	int bx = (int)get_group_id(0);

	if ((long)bx >= dim.number_boxes || tx >= NUMBER_PAR_PER_BOX) return;

	long first_i = box[bx].offset;
	__global FOUR_VECTOR* rA = &rv[first_i];
	__global FOUR_VECTOR* fA = &fv[first_i];

	fp alpha = par.alpha;
	fp a2 = (fp)2.0f * alpha * alpha;

	fp f_v = fA[tx].v;
	fp f_x = fA[tx].x;
	fp f_y = fA[tx].y;
	fp f_z = fA[tx].z;

	for (int k = 0; k < (1 + box[bx].nn); k++) {
		int pointer = (k == 0) ? bx : box[bx].nei[k - 1].number;
		long first_j = box[pointer].offset;

		__global FOUR_VECTOR* rB = &rv[first_j];
		__global fp* qB = &qv[first_j];

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
			fp r2 = rA[tx].v + rB[j].v - DOT(rA[tx], rB[j]);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = (fp)2.0f * vij;

			fp dx = rA[tx].x - rB[j].x;
			fp dy = rA[tx].y - rB[j].y;
			fp dz = rA[tx].z - rB[j].z;

			fp fxij = fs * dx;
			fp fyij = fs * dy;
			fp fzij = fs * dz;

			fp q = qB[j];
			f_v += q * vij;
			f_x += q * fxij;
			f_y += q * fyij;
			f_z += q * fzij;
		}
	}

	fA[tx].v = f_v;
	fA[tx].x = f_x;
	fA[tx].y = f_y;
	fA[tx].z = f_z;
}
